#include <iostream>
#include <atomic>
using namespace std;

struct Node {
    atomic<Node*> next{nullptr};
    int data;
    Node(int d) : data(d) {}
};

class LockFreeStack {
    atomic<Node*> head{nullptr};
public:
    void push(int data) {
        Node* new_node = new Node(data);
        new_node->next = head.load();
        while (!head.compare_exchange_weak(new_node->next, new_node));
    }

    bool pop(int& result) {
        Node* old_head = head.load();
        while (old_head && !head.compare_exchange_weak(old_head, old_head->next));
        if (old_head) {
            result = old_head->data;
            delete old_head;
            return true;
        }
        return false;
    }
};

int main() {
    LockFreeStack stack;
    stack.push(42);
    int value;
    cout << stack.pop(value) << value;
    return 0;
}

