#include <iostream>
#include <array>
using namespace std;

template<size_t N>
constexpr auto sieve_of_eratosthenes() {
    array<bool, N> is_prime{};
    is_prime.fill(true);
    is_prime[0] = is_prime[1] = false;

    for (size_t i = 2; i * i < N; ++i) {
        if (is_prime[i]) {
            for (size_t j = i * i; j < N; j += i) {
                is_prime[j] = false;
            }
        }
    }

    size_t count = 0;
    for (size_t i = 2; i < N; ++i) {
        if (is_prime[i]) ++count;
    }
    return count;
}

int main() {
    constexpr auto primes = sieve_of_eratosthenes<20>();
    cout << primes;
    return 0;
}

