template<size_t N>
constexpr auto compile_time_hash(const char (&str)[N]) {
    constexpr size_t FNV_PRIME = 1099511628211ULL;
    constexpr size_t FNV_OFFSET = 14695981039346656037ULL;

    size_t hash = FNV_OFFSET;
    for (size_t i = 0; i < N - 1; ++i) {
        hash ^= static_cast<size_t>(str[i]);
        hash *= FNV_PRIME;
    }
    return hash;
}

int main() {
    constexpr auto hash1 = compile_time_hash("hello");
    constexpr auto hash2 = compile_time_hash("world");
    cout << (hash1 != hash2);
    return 0;
}

