#include <iostream>
#include <array>
using namespace std;

template<size_t N>
constexpr auto fibonacci_matrix_power() {
    array<array<long long, 2>, 2> result = {{{1, 0}, {0, 1}}};
    array<array<long long, 2>, 2> base = {{{1, 1}, {1, 0}}};

    size_t exp = N;
    while (exp > 0) {
        if (exp & 1) {
            auto temp = result;
            result[0][0] = temp[0][0] * base[0][0] + temp[0][1] * base[1][0];
            result[0][1] = temp[0][0] * base[0][1] + temp[0][1] * base[1][1];
            result[1][0] = temp[1][0] * base[0][0] + temp[1][1] * base[1][0];
            result[1][1] = temp[1][0] * base[0][1] + temp[1][1] * base[1][1];
        }
        auto temp = base;
        base[0][0] = temp[0][0] * temp[0][0] + temp[0][1] * temp[1][0];
        base[0][1] = temp[0][0] * temp[0][1] + temp[0][1] * temp[1][1];
        base[1][0] = temp[1][0] * temp[0][0] + temp[1][1] * temp[1][0];
        base[1][1] = temp[1][0] * temp[0][1] + temp[1][1] * temp[1][1];
        exp >>= 1;
    }
    return result[0][1];
}

int main() {
    constexpr auto fib10 = fibonacci_matrix_power<10>();
    cout << fib10;
    return 0;
}

#include <iostream>
