template<int... Ns>
struct int_list {};

template<int N, typename List>
struct insert;

template<int N>
struct insert<N, int_list<>> {
    using type = int_list<N>;
};

template<int N, int Head, int... Tail>
struct insert<N, int_list<Head, Tail...>> {
    using type = conditional_t<(N <= Head),
        int_list<N, Head, Tail...>,
        typename insert<N, int_list<Tail...>>::type::template prepend<Head>
    >;
};

template<int... Ns>
struct int_list {
    template<int N>
    using prepend = int_list<N, Ns...>;
};

template<typename List>
struct sort;

template<>
struct sort<int_list<>> {
    using type = int_list<>;
};

template<int Head, int... Tail>
struct sort<int_list<Head, Tail...>> {
    using type = typename insert<Head, typename sort<int_list<Tail...>>::type>::type;
};

template<typename List>
struct sum;

template<int... Ns>
struct sum<int_list<Ns...>> {
    static constexpr int value = (Ns + ...);
};

