}

#include <iostream>
#include <type_traits>
using namespace std;

template<size_t N, size_t K>
struct binomial_coefficient {
    static constexpr size_t value = 
        (K == 0 || K == N) ? 1 :
        binomial_coefficient<N-1, K-1>::value + binomial_coefficient<N-1, K>::value;
};

template<size_t N>
struct catalan_number {
    static constexpr size_t value = 
        (N == 0) ? 1 :
        binomial_coefficient<2*N, N>::value / (N + 1);
};

int main() {
    constexpr auto cat4 = catalan_number<4>::value;
    cout << cat4;
    return 0;
}

#include <iostream>
#include <type_traits>
using namespace std;

template<typename T>
struct type_wrapper { using type = T; };

template<template<typename> class F, typename List>
struct map;

template<template<typename> class F, template<typename...> class List, typename... Ts>
struct map<F, List<Ts...>> {
    using type = List<typename F<Ts>::type...>;
};

template<typename T>
using add_pointer = type_wrapper<T*>;

template<typename T>
using add_const = type_wrapper<const T>;

template<typename... Ts>
struct type_list {};

template<typename List>
struct count_pointers;

template<typename... Ts>
struct count_pointers<type_list<Ts...>> {
    static constexpr size_t value = (is_pointer_v<Ts> + ...);
};

int main() {
    using original = type_list<int, float, char>;
    using with_pointers = typename map<add_pointer, original>::type;
    cout << count_pointers<with_pointers>::value;
    return 0;
}
